%%%%%%%%%% Function trexLogReadV01.m %%%%%%%%%%% TREX Log Reader ver.1%% Kei Nakamura% Created on Friday, November 10th 2006.% Modified on%% function [logTtl,logDat,ingTtl,infDat] = trexLogReadV01(day,logNam);% reads and returnes log and inf of guiding part.function [logTtl,logDat,infTtl,infDat] = trexLogReadV01(day,logNam);  %function headerif day>=6;    [logTtl,logDat] = fLogRead1(logNam{1});    [infTtl,infDat] = vrnInfRead(logNam{2});else    logDat = textread(logNam{1});    [infTtl,infDat,logTtl] = vrnInfRead2(logNam{2});end
